INSERT ALL

    WHEN NOT EXISTS (
        SELECT 1
        FROM system_user_group_project_r t
        WHERE t.user_group_id = #{r.userGroupId}
        AND t.project_id = #{r.projectId}
        AND t.deleted = 0
    ) THEN
    INTO system_user_group_project_r (
        id, user_group_id, project_id, create_time, creator, update_time, updater, deleted
        ) VALUES (
        #{r.id}, #{r.userGroupId}, #{r.projectId}, #{r.createTime}, #{r.creator},
        #{r.updateTime}, #{r.updater}, #{r.deleted}
    )

SELECT 1 FROM DUAL
